import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { formatDate } from './formatDate';

describe('formatDate', () => {
  // Happy path: typical ISO string
  it('should handle happy path with a valid ISO date string', () => {
    const iso = '2023-08-15T13:45:30.000Z';
    // Expected format could be "August 15, 2023" – adjust based on actual implementation
    const result = formatDate(iso);
    expect(result).toMatch(/^\w+ \d{1,2}, \d{4}$/);
  });

  // Edge case: date without time component or different timezone offset
  it('should handle edge case with date only or timezone offset', () => {
    // Date‑only ISO string
    const isoDateOnly = '2023-12-01';
    const resultDateOnly = formatDate(isoDateOnly);
    expect(resultDateOnly).toMatch(/^\w+ \d{1,2}, \d{4}$/);

    // ISO string with offset
    const isoWithOffset = '2023-08-15T13:45:30+05:00';
    const resultWithOffset = formatDate(isoWithOffset);
    expect(resultWithOffset).toMatch(/^\w+ \d{1,2}, \d{4}$/);
  });

  // Null / empty handling
  it('should handle null/empty inputs gracefully', () => {
    // undefined
    expect(() => formatDate(undefined as any)).toThrow();

    // null
    expect(() => formatDate(null as any)).toThrow();

    // empty string
    expect(() => formatDate('')).toThrow();

    // zero (not a string)
    expect(() => formatDate(0 as any)).toThrow();
  });
});

