import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Import the function under test.
// Adjust the path according to the actual project structure.
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  beforeEach(() => {
    // No external module dependencies to mock for this simple utility.
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path: truncate long content to the default maxLength', () => {
    const longText = 'a'.repeat(150);
    const result = truncateContent(longText);
    // Expect the result length to be at most the default maxLength (80)
    expect(result.length).toBeLessThanOrEqual(80);
    // When truncation occurs, the original content should not be fully retained
    expect(result).not.toBe(longText);
  });

  it('should handle edge case: content exactly equals maxLength', () => {
    const exactText = 'b'.repeat(80);
    const result = truncateContent(exactText, 80);
    // No truncation should happen; result should be identical to input
    expect(result).toBe(exactText);
    expect(result.length).toBe(80);
  });

  it('should handle null/empty inputs gracefully', () => {
    // Null input
    // @ts-ignore – intentionally passing null to test handling
    expect(truncateContent(null)).toBe('');
    // Undefined input
    // @ts-ignore – intentionally passing undefined to test handling
    expect(truncateContent(undefined)).toBe('');
    // Empty string input
    expect(truncateContent('')).toBe('');
    // Zero as maxLength should return empty string regardless of content
    expect(truncateContent('some content', 0)).toBe('');
  });
});

